// NODE B — Attach history to webhook data
// This merges the Google Sheets history with the incoming webhook payload
// so Build Claude Payload can pass BOTH to Claude in one call.

const webhookBody = $('GitHub CI Webhook').first().json.body;

// Read last 5 runs from Sheets (slice(-5) = most recent 5 rows)
let history = [];
try {
  const rows = $('Read History').all();
  if (rows.length > 0 && rows[0].json.Failed_Tests !== undefined) {
    history = rows
      .slice(-5)
      .map(r => ({
        date: r.json.Date,
        branch: r.json.Branch,
        failed: r.json.Failed_Tests
          ? r.json.Failed_Tests.split(',').map(s => s.trim()).filter(Boolean)
          : []
      }));
  }
} catch(e) {
  // If sheet is empty or unreadable, just use empty history — don't crash
  history = [];
}

// Return webhook data WITH history attached
return [{ json: { ...webhookBody, history } }];

// NODE C — Extract failed test names cleanly for logging to Sheets
// Runs after Format PR Comment, feeds into Append Row to Sheets

const analysis = $('Format PR Comment').first().json.analysis;
const webhookBody = $('Format PR Comment').first().json;

// Get unique failed test names as a comma-separated string
const failedNames = (analysis.failed_tests || [])
  .map(t => t.name)
  .filter((v, i, a) => a.indexOf(v) === i)  // remove duplicates
  .join(', ');

// Get flaky test names detected this run
const flakyNames = (analysis.flaky_tests || [])
  .map(t => t.name)
  .join(', ');

return [{
  json: {
    Date: new Date().toLocaleString('en-SG', { timeZone: 'Asia/Singapore' }),
    Branch: webhookBody.branch || '',
    Run_ID: webhookBody.run_id || '',
    Health: analysis.run_summary.overall_health,
    Total: analysis.run_summary.total_tests,
    Passed: analysis.run_summary.passed,
    Failed: analysis.run_summary.failed,
    Failed_Tests: failedNames,
    Flaky_Tests: flakyNames
  }
}];

// Build Claude API request body — TRIMMED to avoid rate limits
// Now reads from 'Merge History' instead of directly from webhook
const webhookBody = $input.first().json;
const testResults = webhookBody.test_results || [];
const history = webhookBody.history || [];

// Trim: full detail for failed/skipped, name+suite only for passed
const trimmed = testResults.map(suite => {
  const failed = (suite.tests || []).filter(t => t.status !== 'passed');
  const passed = (suite.tests || []).filter(t => t.status === 'passed');
  return {
    source: suite.source,
    summary: suite.summary,
    failed_tests: failed,
    passed_sample: passed.slice(0, 10).map(t => ({ name: t.name, suite: t.suite })),
    total_passed_not_shown: Math.max(0, passed.length - 10)
  };
});

// Detect if playwright data is present
const hasPW = testResults.some(r => r.source === 'playwright');

const systemPrompt = `You are a software testing analyst covering Jest unit/integration tests AND Playwright UI tests. Analyse all provided test suites and return ONLY valid JSON - no markdown, no preamble - matching this schema exactly:
{"run_summary":{"total_tests":0,"passed":0,"failed":0,"skipped":0,"overall_health":"healthy|degraded|critical","health_reason":"string","suites":{"backend":{"total":0,"passed":0,"failed":0},"frontend":{"total":0,"passed":0,"failed":0},"integration":{"total":0,"passed":0,"failed":0},"playwright":{"total":0,"passed":0,"failed":0}}},"failed_tests":[{"name":"string","suite":"string","source":"backend|frontend|integration|playwright","failure_type":"assertion_error|timeout|selector_not_found|navigation_error|import_error|setup_teardown|unexpected_exception|unknown","error_message":"string","fix_hint":"string"}],"brittle_tests":[{"name":"string","suite":"string","source":"string","reason":"string","recommendation":"string"}],"anti_patterns":[{"suite":"string","source":"string","pattern":"string","details":"string"}],"flaky_tests":[{"name":"string","suite":"string","fail_count_last_5":0,"recommendation":"string"}],"suggested_new_test":{"test_name":"string","target_suite":"string","source":"string","what_to_assert":"string","rationale":"string"},"top_priority_fixes":["string"]}

Rules:
- failure_type selector_not_found and navigation_error are for Playwright only
- For Playwright failures, fix_hint should reference the specific selector or page action
- If error_message is empty, write No error captured (do not explain why in error_message, save explanation for fix_hint)
- If error_message is empty but test references a UI element, classify as selector_not_found
- If error_message is empty and fix_hint references missing fixtures, classify as setup_teardown
- For flaky_tests: a test is flaky if it appears in failed list of 2 or more of the last 5 historical runs
- Each brittle_tests entry must have a UNIQUE reason — do not repeat the same explanation
- top_priority_fixes max 3 items ordered by severity
- empty arrays if nothing found, never omit fields`;

// Include history so Claude can detect flaky tests
const userMessage = `Analyse these test results (branch: ${webhookBody.branch}, actor: ${webhookBody.actor}, has_playwright: ${hasPW}).

Historical context from last ${history.length} runs (use this to detect flaky tests):
${JSON.stringify(history)}

Current run results:
${JSON.stringify(trimmed)}`;

const claudeBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 2048,
  system: systemPrompt,
  messages: [{ role: 'user', content: userMessage }]
};

return [{ json: { claudeBody: JSON.stringify(claudeBody), webhookBody } }];

const claudeResponse = $input.first().json;
const rawText = claudeResponse.content[0].text.trim();
let analysis;
try {
  const cleaned = rawText.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  throw new Error(`Claude returned invalid JSON: ${rawText.substring(0, 300)}`);
}

const s = analysis.run_summary;
const webhookBody = $('Build Claude Payload').first().json.webhookBody;
const healthEmoji = s.overall_health === 'healthy' ? '✅' : s.overall_health === 'degraded' ? '⚠️' : '🔴';

let comment = `## ${healthEmoji} AI Test Analysis — ${s.overall_health.toUpperCase()}\n\n`;
comment += `> ${s.health_reason}\n\n`;

// Overall metrics table
comment += `| Metric | Value |\n|--------|-------|\n`;
comment += `| Total Tests | ${s.total_tests} |\n`;
comment += `| ✅ Passed | ${s.passed} |\n`;
comment += `| ❌ Failed | ${s.failed} |\n`;
comment += `| ⏭ Skipped | ${s.skipped || 0} |\n\n`;

// Per-suite breakdown (only show suites that have data)
if (s.suites) {
  const suiteRows = Object.entries(s.suites)
    .filter(([_, v]) => v.total > 0)
    .map(([name, v]) => {
      const icon = name === 'playwright' ? '🎭' : name === 'backend' ? '⚙️' : name === 'frontend' ? '🖥️' : '🔗';
      const status = v.failed > 0 ? '❌' : '✅';
      return `| ${icon} ${name} | ${v.total} | ${v.passed} | ${v.failed} | ${status} |`;
    });
  if (suiteRows.length > 0) {
    comment += `### 📊 Suite Breakdown\n\n`;
    comment += `| Suite | Total | Passed | Failed | Status |\n`;
    comment += `|-------|-------|--------|--------|--------|\n`;
    comment += suiteRows.join('\n') + '\n\n';
  }
}

// Failed tests — split Jest and Playwright
if (analysis.failed_tests && analysis.failed_tests.length > 0) {
  const jestFailed = analysis.failed_tests.filter(t => t.source !== 'playwright');
  const pwFailed = analysis.failed_tests.filter(t => t.source === 'playwright');
  if (jestFailed.length > 0) {
    comment += `### ❌ Failed Tests (Jest)\n\n`;
    for (const t of jestFailed) {
      comment += `**${t.name}** (\`${t.suite}\`)\n`;
      comment += `- Type: \`${t.failure_type}\` | Error: ${t.error_message}\n`;
      comment += `- 💡 ${t.fix_hint}\n\n`;
    }
  }
  if (pwFailed.length > 0) {
    comment += `### 🎭 Failed Tests (Playwright UI)\n\n`;
    for (const t of pwFailed) {
      comment += `**${t.name}** (\`${t.suite}\`)\n`;
      comment += `- Type: \`${t.failure_type}\` | Error: ${t.error_message}\n`;
      comment += `- 💡 ${t.fix_hint}\n\n`;
    }
  }
}

// Flaky tests — NEW section powered by memory
if (analysis.flaky_tests && analysis.flaky_tests.length > 0) {
  comment += `### 🎲 Flaky Tests (detected across runs)\n\n`;
  for (const t of analysis.flaky_tests) {
    comment += `- **${t.name}** — failed ${t.fail_count_last_5}/5 recent runs. ${t.recommendation}\n`;
  }
  comment += '\n';
}

// Brittle tests
if (analysis.brittle_tests && analysis.brittle_tests.length > 0) {
  comment += `### ⚠️ Brittle Tests\n\n`;
  for (const t of analysis.brittle_tests) {
    const src = t.source ? ` · ${t.source}` : '';
    comment += `- **${t.name}**${src} — ${t.reason}\n`;
  }
  comment += '\n';
}

// Top priority fixes
if (analysis.top_priority_fixes && analysis.top_priority_fixes.length > 0) {
  comment += `### 🎯 Top Priority Fixes\n\n`;
  analysis.top_priority_fixes.forEach((fix, i) => { comment += `${i+1}. ${fix}\n`; });
  comment += '\n';
}

// Suggested new test
if (analysis.suggested_new_test && analysis.suggested_new_test.test_name) {
  const sug = analysis.suggested_new_test;
  const srcLabel = sug.source ? ` (${sug.source})` : '';
  comment += `### 💡 Suggested New Test${srcLabel}\n`;
  comment += `**${sug.test_name}** — ${sug.what_to_assert}\n\n`;
}

comment += `---\n*Powered by Claude AI · [View CI run](https://github.com/${webhookBody.repo}/actions/runs/${webhookBody.run_id})*`;

return [{
  json: {
    ...webhookBody,
    analysis,
    pr_comment: comment,
    has_pr: !!(webhookBody.pr_number && webhookBody.pr_number !== '' && webhookBody.pr_number !== 'undefined')
  }
}];
